var sm = new sn_ws.SOAPMessageV2('Legacy ERP', 'GetOrderStatus');
var response = sm.execute();
gs.info('SOAP status: ' + response.getStatusCode());

var priority = 1;
var queue = priority == 1 ? 'Major Incident Desk' : 'Service Desk';
gs.info(queue);

var hour = new GlideDateTime().getDisplayValueInternal().split(' ')[1].split(':')[0];
var allowed = parseInt(hour, 10) >= 20 || parseInt(hour, 10) < 2;
gs.info('Deployment window open: ' + allowed);
